class Solution:
    def checkTwoChessboards(self, coordinate1, coordinate2):
        # Independent implementation enumerating the full 8x8 color pattern
        # instead of computing parity arithmetically.
        board = {}
        for ci, col in enumerate('abcdefgh'):
            for row in range(1, 9):
                board[col + str(row)] = (ci + row) % 2
        return board[coordinate1] == board[coordinate2]

